When trying to compile code with case inside statements I get the following error:
%Error: inside_tst.sv:10: syntax error, unexpected inside, expecting endcase

Example code:
```
module inside_test (
                  clk
                  );

    reg [3:0] a;
    reg [3:0] b;
    reg [3:0] c;

    always @ (/*AS*/a) begin
      case ( a ) inside
        'h1, 'h2, 'h3: b = 'h0;
        'h4: b = 'h1
        ['h7:'hf]: b = 'h2;
        default: b = 'hffff;
      endcase
    end 

    always @ (/*AS*/a) begin
      case ( a ) inside
        'b000?: c = 'h0;
        'b01??: c = 'h2;
        'b10?0: c = 'h3;
        default: c = 'h4;

    always @ (posedge clk) begin
      a = a + 1;
    end

endmodule // inside_test

```
